        if not self.tokens:
            raise ValueError("Empty expression")
        node = self.expression()
        if self.peek() is not None:
            raise ValueError("Extra tokens after expression")
        return node

    def expression(self):
        """Parse addition and subtraction (lowest precedence)."""
        node = self.term()
